import base64, hashlib, hmac, sys

HDR=b"X3"; NONCE_LEN=16; TAG_LEN=32

def _split_keys(master_key: bytes):
    enc_key = hashlib.sha256(master_key + b"enc").digest()
    mac_key = hashlib.sha256(master_key + b"mac").digest()
    return enc_key, mac_key

def _ks(enc_key: bytes, nonce: bytes):
    c=0
    while True:
        yield hashlib.sha256(enc_key + nonce + c.to_bytes(8,"big")).digest(); c+=1

def _xor(data: bytes, ks):
    out=bytearray(len(data)); i=0; buf=b""
    for n,b in enumerate(data):
        if i>=len(buf): buf=next(ks); i=0
        out[n]=b ^ buf[i]; i+=1
    return bytes(out)

B64=""
KEY=bytes([206,15,73,233,117,215,38,55,186,137,121,218,45,188,207,89,255,83,119,239,138,30,106,155,161,218,162,212,74,239,9,235])

def main():
    blob = base64.b64decode(B64.encode("ascii"))
    if len(blob) < 2+NONCE_LEN+TAG_LEN or blob[:2]!=HDR:
        print("Corrupt payload."); sys.exit(1)
    nonce = blob[2:2+NONCE_LEN]
    ct    = blob[2+NONCE_LEN:-TAG_LEN]
    tag   = blob[-TAG_LEN:]

    enc_key, mac_key = _split_keys(KEY)
    calc = hmac.new(mac_key, nonce+ct, hashlib.sha256).digest()
    if not hmac.compare_digest(calc, tag):
        print("Integrity check failed."); sys.exit(2)

    pt = _xor(ct, _ks(enc_key, nonce))
    code = compile(pt, "<sealed>", "exec")
    g = {"__name__":"__main__","__file__":"<sealed>"}
    exec(code, g)

if __name__=="__main__":
    try: sys.settrace(lambda *a,**k: None)
    except Exception: pass
    main()
